const dados = $('Validar Dados do Agente').first().json;
const atual = $('Buscar Agendamento Atual').first().json;
const alt = dados.alteracoes || {};
const agora = new Date().toLocaleString('pt-BR', { timeZone: 'America/Bahia' });

const mapaCampos = {
  local: 'local', data: 'Data', horario: 'horario',
  endereco: 'endereco', tecnico: 'técnico', vendedor: 'vendedor', obs: 'obs'
};

const patch = { ID: dados.id_agendamento };
const camposAlterados = [];

for (const [campoIA, coluna] of Object.entries(mapaCampos)) {
  const valorNovo = alt[campoIA];
  const temValor = valorNovo !== undefined && valorNovo !== null && String(valorNovo).trim() !== '';
  patch[coluna] = temValor ? valorNovo : atual[coluna];
  if (temValor) camposAlterados.push(campoIA);
}

patch.Status = dados.acao === 'cancelar' ? 'Cancelado' : atual.Status;
patch.email = atual.email;
patch.UltimaAtualizacao = agora;
patch._debug_camposAlterados = camposAlterados.join(', ') || 'nenhum';
patch._debug_altRecebido = JSON.stringify(alt);

return [{ json: patch }];

let texto = $json.text || $json.textPlain || $json.html || "";
const assunto = $json.subject || "";

// ==============================
// Corrige caracteres (mojibake)
// ==============================
function corrigirTexto(str) {
  if (typeof str !== "string" || !str.length) return "";

  const temMojibake = /Ã[\x80-\xBF]|Â[\x80-\xBF]/.test(str);
  if (!temMojibake) return str;

  try {
    const corrigido = Buffer.from(str, "latin1").toString("utf8");
    if (!corrigido.includes("\uFFFD")) return corrigido;
  } catch (e) {}

  return str;
}

texto = corrigirTexto(texto);

// ==============================
// Remove HTML simples
// ==============================
texto = texto
  .replace(/<br\s*\/?>/gi, "\n")
  .replace(/<\/p>/gi, "\n")
  .replace(/<[^>]+>/g, "");

// ==============================
// Remove imagens embutidas
// ==============================
texto = texto.replace(/\[image:[^\]]*]/gi, "");

// ==============================
// Remove histórico de respostas
// ==============================
const marcadores = [
  /^De:.*$/im,
  /^From:.*$/im,
  /^Em .* escreveu:$/im,
  /^On .* wrote:$/im,
  /^-----Original Message-----$/im,
  /^_{5,}$/im,
  /^>.*$/im
];

for (const regex of marcadores) {
  const pos = texto.search(regex);
  if (pos !== -1) {
    texto = texto.substring(0, pos);
    break;
  }
}

// ==============================
// Remove assinatura comum
// ==============================
const assinaturas = [
  /^Atenciosamente[\s\S]*/im,
  /^Cordialmente[\s\S]*/im,
  /^Abraços[\s\S]*/im,
  /^Abs[\s\S]*/im,
  /^Enviado do meu iPhone[\s\S]*/im,
  /^Enviado do meu Android[\s\S]*/im
];

for (const regex of assinaturas) {
  texto = texto.replace(regex, "");
}

// ==============================
// Remove aviso de confidencialidade
// ==============================
texto = texto.replace(
  /Esta mensagem contém[\s\S]*/i,
  ""
);

// ==============================
// Remove saudação inicial
// ==============================
texto = texto.replace(
  /^(Bom dia|Boa tarde|Boa noite|Olá|Oi)[,!\s]*/i,
  ""
);

// ==============================
// Limpeza final
// ==============================
texto = texto
  .replace(/\r/g, "")
  .replace(/\n{3,}/g, "\n\n")
  .replace(/[ \t]{2,}/g, " ")
  .trim();

return [
  {
    json: {
      assunto,
      email: texto
    }
  }
];
